import React, { useState, useEffect } from 'react';
import axios from 'axios';

function FormPaciente({ onNovoPaciente, pacienteEditando, onFimEdicao }) {
  // Campos individuais
  const [numeroProntuario, setNumeroProntuario] = useState('');
  const [nome, setNome] = useState('');
  const [telefone, setTelefone] = useState('');
  const [mensagem, setMensagem] = useState('');

  // Demais campos em formData
  const [formData, setFormData] = useState({
    numero_gaveta: '',
    rg: '',
    cpf: '',
    data_nascimento: '',
    idade: '',
    cidade: '',
    endereco: '',
    numero: '',
    observacao: ''
  });

  // Popula campos quando em edição
  useEffect(() => {
    if (pacienteEditando) {
      setNumeroProntuario(pacienteEditando.numero_prontuario || '');
      setNome(pacienteEditando.nome || '');
      setTelefone(formatarTelefone(pacienteEditando.telefone || ''));
      setFormData({
        numero_gaveta: pacienteEditando.numero_gaveta || '',
        rg: pacienteEditando.rg || '',
        cpf: pacienteEditando.cpf || '',
        // Garante formato yyyy-MM-dd para date input
        data_nascimento: pacienteEditando.data_nascimento
          ? pacienteEditando.data_nascimento.slice(0, 10)
          : '',
        idade: pacienteEditando.idade ? String(pacienteEditando.idade) : '',
        cidade: pacienteEditando.cidade || '',
        endereco: pacienteEditando.endereco || '',
        numero: pacienteEditando.numero || '',
        observacao: pacienteEditando.observacao || ''
      });
    } else {
      setNumeroProntuario('');
      setNome('');
      setTelefone('');
      setFormData({
        numero_gaveta: '',
        rg: '',
        cpf: '',
        data_nascimento: '',
        idade: '',
        cidade: '',
        endereco: '',
        numero: '',
        observacao: ''
      });
    }
    setMensagem('');
  }, [pacienteEditando]);

  // Formatação de telefone
  function formatarTelefone(campo) {
    const digitos = campo.replace(/\D/g, '');
    if (!digitos) return '';
    if (digitos.length <= 2) {
      return digitos.replace(/^(\d{0,2})/, '($1');
    }
    if (digitos.length <= 6) {
      return digitos.replace(/^(\d{2})(\d{0,4})/, '($1) $2');
    }
    return digitos.replace(/^(\d{2})(\d{5})(\d{0,4}).*/, '($1) $2-$3');
  }

  const handleTelefoneChange = e => {
    setTelefone(formatarTelefone(e.target.value));
  };

  const handleSubmit = async e => {
    e.preventDefault();
    setMensagem('');

    // Valida telefone
    const somenteDigitos = telefone.replace(/\D/g, '');
    if (!(somenteDigitos.length === 10 || somenteDigitos.length === 11)) {
      setMensagem('Telefone inválido. Use 10 ou 11 dígitos.');
      return;
    }

    // Prepara dados para envio
    const dados = {
      numero_prontuario: numeroProntuario.trim() || null,
      nome: nome.trim(),
      telefone: somenteDigitos,
      ...formData
    };

    try {
      if (pacienteEditando) {
        await axios.put(`/api/pacientes/${pacienteEditando.id}`, dados);
        setMensagem('Paciente atualizado com sucesso!');
        onNovoPaciente();
      } else {
        await axios.post('/api/pacientes', dados);
        setMensagem('Paciente cadastrado com sucesso!');
        onNovoPaciente();
        // limpa campos
        setNome('');
        setTelefone('');
        setNumeroProntuario('');
        setFormData({
          numero_gaveta: '',
          rg: '',
          cpf: '',
          data_nascimento: '',
          idade: '',
          cidade: '',
          endereco: '',
          numero: '',
          observacao: ''
        });
      }
    } catch {
      setMensagem(
        pacienteEditando
          ? 'Erro ao atualizar paciente.'
          : 'Erro ao cadastrar paciente.'
      );
    }
  };

  return (
    <div className="bg-white mx-auto max-w-lg rounded-2xl p-6">
      <form onSubmit={handleSubmit} autoComplete="off">
        <h2 className="text-2xl font-bold mb-6 text-gray-800">
          {pacienteEditando ? 'Editar Paciente' : 'Novo Paciente'}
        </h2>

        {/* Número do Prontuário (opcional) e Nº Gaveta */}
        <div className="mb-6 grid grid-cols-2 gap-4">
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Número do Prontuário <small>(opcional)</small>
            </label>
            <input
              type="text"
              maxLength={8}
              value={numeroProntuario}
              onChange={e => setNumeroProntuario(e.target.value)}
              placeholder="Até 8 chars"
              className="w-full border rounded px-3 py-2"
            />
          </div>
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Nº Gaveta <small>(opcional)</small>
            </label>
            <input
              type="text"
              value={formData.numero_gaveta}
              onChange={e => setFormData({ ...formData, numero_gaveta: e.target.value })}
              className="w-full border rounded px-3 py-2"
            />
          </div>
        </div>

        {/* Nome e Sobrenome */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Nome e Sobrenome
            <input
              type="text"
              required
              value={nome}
              onChange={e => setNome(e.target.value)}
              placeholder="Nome e sobrenome"
              className="w-full border rounded px-3 py-2 mt-1"
            />
          </label>
        </div>

        {/* Telefone */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Telefone
            <input
              type="tel"
              required
              value={telefone}
              onChange={handleTelefoneChange}
              placeholder="(XX) XXXXX-XXXX"
              className="w-full border rounded px-3 py-2 mt-1"
            />
          </label>
        </div>

        {/* RG e CPF */}
        <div className="mb-6 grid grid-cols-2 gap-4">
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              RG <small>(opcional)</small>
            </label>
            <input
              type="text"
              value={formData.rg}
              onChange={e => setFormData({ ...formData, rg: e.target.value })}
              className="w-full border rounded px-3 py-2"
            />
          </div>
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              CPF <small>(opcional)</small>
            </label>
            <input
              type="text"
              value={formData.cpf}
              onChange={e => setFormData({ ...formData, cpf: e.target.value })}
              placeholder="000.000.000-00"
              className="w-full border rounded px-3 py-2"
            />
          </div>
        </div>

        {/* Data de Nascimento e Idade */}
        <div className="mb-6 grid grid-cols-2 gap-4">
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Data de Nascimento <small>(opcional)</small>
            </label>
            <input
              type="date"
              value={formData.data_nascimento || ''}
              onChange={e => setFormData({ ...formData, data_nascimento: e.target.value })}
              className="w-full border rounded px-3 py-2"
            />
          </div>
          <div>
            <label className="block mb-2 font-medium text-gray-700">
              Idade <small>(opcional)</small>
            </label>
            <input
              type="number"
              value={formData.idade}
              onChange={e => setFormData({ ...formData, idade: e.target.value })}
              className="w-full border rounded px-3 py-2"
            />
          </div>
        </div>

        {/* Endereço, Número e Cidade */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Endereço e Número <small>(opcional)</small>
          </label>
          <div className="flex gap-4">
            <input
              type="text"
              placeholder="Endereço"
              value={formData.endereco}
              onChange={e => setFormData({ ...formData, endereco: e.target.value })}
              className="w-3/4 border rounded px-3 py-2"
            />
            <input
              type="text"
              placeholder="Número"
              value={formData.numero}
              onChange={e => setFormData({ ...formData, numero: e.target.value })}
              className="w-1/4 border rounded px-3 py-2"
            />
          </div>
        </div>
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Cidade <small>(opcional)</small>
          </label>
          <input
            type="text"
            value={formData.cidade}
            onChange={e => setFormData({ ...formData, cidade: e.target.value })}
            className="w-full border rounded px-3 py-2"
          />
        </div>

        {/* Observação */}
        <div className="mb-6">
          <label className="block mb-2 font-medium text-gray-700">
            Observação <small>(opcional)</small>
          </label>
          <textarea
            value={formData.observacao}
            onChange={e => setFormData({ ...formData, observacao: e.target.value })}
            className="w-full border rounded px-3 py-2"
          />
        </div>

        {/* Botões */}
        <div className="flex flex-col md:flex-row gap-4">
          <button
            type="submit"
            className="bg-[#1A1C2C] hover:bg-[#3B4854] text-white font-bold py-2 px-6 rounded-full"
          >
            {pacienteEditando ? 'Atualizar' : 'Cadastrar'}
          </button>
          {pacienteEditando && (
            <button
              type="button"
              className="bg-[#DA3648] text-white hover:bg-[#BC3140] px-4 py-2 rounded-full"
              onClick={onFimEdicao}
            >
              Cancelar
            </button>
          )}
        </div>

        {/* Feedback */}
        {mensagem && <p className="mt-4 text-red-600">{mensagem}</p>}
      </form>
    </div>
  );
}

export default FormPaciente;
